#!/usr/bin/env ruby

# This was mostly generated by Gemini.

def abbreviate_version(current, new)
  # Find the index of the first differing character
  diff_index = current.chars.zip(new.chars).find_index { |c, n| c != n }
  
  # return new unless diff_index # No difference found
  # If there's no diff, it means that either one is a prefix of the
  # other or they're equal. Assume it's current that's the shorter,
  # this doesn't quite do the right thing in the other cases, but they
  # shouldn't happen.
  diff_index = current.length - 1 unless diff_index

  # Go backwards from the character *before* the diff to find the preceding segment separator ('.', '-', or '+').
  i = diff_index - 1
  while i >= 0 && current[i] =~ /[a-zA-Z0-9]/
    i -= 1
  end
  
  # If we stopped at a separator, the abbreviation starts at that separator's index.
  # Otherwise, it starts at the original diff index.
  if i >= 0 && current[i] =~ /[\.\-\+]/
    start_index = i
  else
    start_index = diff_index
  end
  
  new[start_index..-1]
end

# Read all data from STDIN
data = STDIN.read
lines = data.split("\n").reject(&:empty?)

packages = []

lines.each do |line|
  # Regex to capture:
  # 1. Package name (until /)
  # 2. New version (2nd word)
  # 3. Current version (in brackets)
  match = line.match(/^([^\/]+)\/.*?\s+(\S+).*?\[upgradable from:\s*([^\]]+)\]/)
  
  if match
    package_name = match[1]
    new_version = match[2]
    current_version = match[3].strip
    
    packages << {
      name: package_name,
      new_version: new_version,
      current_version: current_version
    }
  end
end

# Calculate column widths for alignment
max_name_len = packages.map { |p| p[:name].length }.max || 0
max_current_version_len = packages.map { |p| p[:current_version].length }.max || 0

# Define format strings for alignment
# Adding 1 to the max length for a little space
name_fmt = "%-#{max_name_len}s"
current_ver_fmt = "%#{max_current_version_len}s"

formatted = packages.collect do |p|
  abbreviated_version = abbreviate_version(p[:current_version], p[:new_version])
  
  # Format the line: <packagename> <current version> -> <new version>
  "#{name_fmt % p[:name]} #{current_ver_fmt % p[:current_version]} -> #{abbreviated_version}"
end

if formatted.size.positive?
  biggest = formatted.max_by { |item| item.length }
  columns = [(80 / (biggest.length + 3)).floor, 1].max

  # How much space do we have to pass out?
  space_leftover = ((80 - (columns * biggest.length)).floor)

  spacing = " " * [(space_leftover / (columns + 1)).floor, 0].max

  formatted.each_slice(columns) { |items|
    puts items.join(spacing)
  }
end
